import{_ as e,o as i,c as s,ag as t}from"./chunks/framework.DXGyWiRo.js";const n="/media/202410/2024-10-30_172336_9983250.11618490235264989.png",l="/media/202305/2023-05-03_145838_5743850.7537485922594406.png",_=JSON.parse('{"title":"AIUI 平台能力概述","description":"","frontmatter":{"title":"AIUI 平台能力概述"},"headers":[],"relativePath":"platform-service/capabilities.md","filePath":"platform-service/capabilities.md","lastUpdated":null}'),r={name:"platform-service/capabilities.md"};function o(p,a,h,d,c,u){return i(),s("div",null,[...a[0]||(a[0]=[t('<p>概述</p><p>AIUI平台主要提供设备端离线能力、服务端在线能力，并提供多种交互模式，具体可参考：</p><h2 id="设备端能力-离线" tabindex="-1">设备端能力（离线） <a class="header-anchor" href="#设备端能力-离线" aria-label="Permalink to &quot;设备端能力（离线）&quot;">​</a></h2><h3 id="_1-1-前端声学" tabindex="-1">1.1. 前端声学 <a class="header-anchor" href="#_1-1-前端声学" aria-label="Permalink to &quot;1.1. 前端声学&quot;">​</a></h3><p>用降噪、回声消除算法来提高唤醒率、识别率。</p><ul><li><strong>麦克风阵列</strong> 多麦克风算法，提高远距离识别率。常见阵列如下：</li></ul><p><img src="'+n+'" alt="" title="null"></p><ul><li><strong>波束形成</strong> 使拾音具有指向性，抑制波束外声音。2麦波束示例： <img src="'+l+`" alt="" title="null"></li><li><strong>回声消除</strong> 回声消除算法抑制麦克风音频中的喇叭声，提高识别率。</li><li><strong>混响消除</strong> 声波在室内传播时，被墙壁反射形成反射声，并和直达声叠加，构成混响。去混响算法消减声音中的反射声，提升声音的清晰度。</li><li><strong>噪音抑制</strong> 降噪算法抑制背景噪声，从而提升唤醒率和识别率。</li><li><strong>声源定位</strong> 唤醒时，根据声音到不同麦克风的时延来确认声音的方位。</li></ul><h3 id="_1-2-语音唤醒" tabindex="-1">1.2. 语音唤醒 <a class="header-anchor" href="#_1-2-语音唤醒" aria-label="Permalink to &quot;1.2. 语音唤醒&quot;">​</a></h3><p>用3-6个字的唤醒词，将设备从休眠状态变成识别状态</p><h3 id="_1-3-离线语音识别" tabindex="-1">1.3. 离线语音识别 <a class="header-anchor" href="#_1-3-离线语音识别" aria-label="Permalink to &quot;1.3. 离线语音识别&quot;">​</a></h3><p>满足无网络环境下的识别需求。支持标点、和实时出字</p><h3 id="_1-4-自定义命令词" tabindex="-1">1.4. 自定义命令词 <a class="header-anchor" href="#_1-4-自定义命令词" aria-label="Permalink to &quot;1.4. 自定义命令词&quot;">​</a></h3><p>支持开发者自定义命令词，最大300词</p><h3 id="_1-5-离线语义-语法匹配" tabindex="-1">1.5. 离线语义（语法匹配） <a class="header-anchor" href="#_1-5-离线语义-语法匹配" aria-label="Permalink to &quot;1.5. 离线语义（语法匹配）&quot;">​</a></h3><p>离线语义支持128个槽位、30000个词条，支持用户自由说，可以实现设备的精细控制；配合本地内容资源，还可以满足特定领域语义理解，实现纯离线语音交互，如户外拉杆箱（点歌机）或车载KTV的离线语音点歌。</p><p><code>注意：离线语义资源消耗：2核1.4G设备，占用CPU15%、内存70M</code></p><h3 id="_1-6-离线合成" tabindex="-1">1.6. 离线合成 <a class="header-anchor" href="#_1-6-离线合成" aria-label="Permalink to &quot;1.6. 离线合成&quot;">​</a></h3><p>支持多种语种的合成，支持音量、语速调节。</p><h2 id="服务端能力-在线" tabindex="-1">服务端能力（在线） <a class="header-anchor" href="#服务端能力-在线" aria-label="Permalink to &quot;服务端能力（在线）&quot;">​</a></h2><h3 id="_2-1-语音识别" tabindex="-1">2.1. 语音识别 <a class="header-anchor" href="#_2-1-语音识别" aria-label="Permalink to &quot;2.1. 语音识别&quot;">​</a></h3><p>语音识别将声音转换为文本。支持方言。</p><ul><li><strong>近场识别</strong> 人距离设备 &lt; 1m</li><li><strong>远场识别</strong> 人距离设备 1~5m</li></ul><p><code>注：远场识别引擎，让远距离识别率更高。</code></p><ul><li><strong>方言识别</strong> AIUI 支持23 种方言，可动态切换方言引擎。 <code>注意：语义理解只支持普通话，方言识别会降低语义理解的效果</code></li><li><strong>持续录音，连续识别</strong> 交互模式支持**单轮交互（Oneshot（单轮交互））**和 <strong>全双工（Continuous）</strong></li></ul><p><strong>Oneshot（单轮交互）</strong>: 一次唤醒，一次交互。如手机 APP 或者语音电视遥控器等单麦克风设备，一般使用单轮交互，需要用户或程序主动触发录音。</p><p><strong>Continuous</strong>：一次唤醒，连续交互。设备需要很好的回声消除效果，且环境安静，<code>否则自言自语</code>。</p><p><code>注意：语音活动检测(Voice Activity Detection,VAD)。用于判断一句话的开始与结束。</code></p><ul><li><strong>拒识，过滤无效语音</strong> 全双工模式，通过语义拒识技术，将无效的噪音和无意义语音进行过滤。</li></ul><p><code>注意：全双工模式仍有小概率的误触发问题。</code></p><h3 id="_2-2-语义理解" tabindex="-1">2.2. 语义理解 <a class="header-anchor" href="#_2-2-语义理解" aria-label="Permalink to &quot;2.2. 语义理解&quot;">​</a></h3><p>语义理解（NLP（语义理解））指将自然语言转化为结构化数据。</p><p>例：将“合肥天气”处理成JSON数据：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;city&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;合肥&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">，</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;time&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2018-01-19&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_2-3-敏感词过滤" tabindex="-1">2.3. 敏感词过滤 <a class="header-anchor" href="#_2-3-敏感词过滤" aria-label="Permalink to &quot;2.3. 敏感词过滤&quot;">​</a></h3><p>敏感词指涉黄、涉暴、涉政、涉恐等词汇。 敏感过滤把敏感词屏蔽，不展示给用户，默认关闭，可<a href="mailto:aiui_support@iflytek.com" target="_blank" rel="noreferrer">联系AIUI开启</a>。</p><h3 id="_2-4-语音合成" tabindex="-1">2.4. 语音合成 <a class="header-anchor" href="#_2-4-语音合成" aria-label="Permalink to &quot;2.4. 语音合成&quot;">​</a></h3><p>语音合成（TTS（语音合成））指将文字转化为声音。支持方言，外语发音人，也支持定制发音人。</p><h3 id="_2-5-信源内容" tabindex="-1">2.5. 信源内容 <a class="header-anchor" href="#_2-5-信源内容" aria-label="Permalink to &quot;2.5. 信源内容&quot;">​</a></h3><p>内容（信源）指语义理解后的有效数据，例如天气信息，音乐的播放链接。AIUI 技能商店中多数技能包含内容。我们诚邀内容提供商与我们合作，包括但不限于音视频资源、流媒体、新闻、自媒体、儿童故事与游戏、股票违章查询等功能类资源。</p><h3 id="_2-6-语音翻译" tabindex="-1">2.6. 语音翻译 <a class="header-anchor" href="#_2-6-语音翻译" aria-label="Permalink to &quot;2.6. 语音翻译&quot;">​</a></h3><p>AIUI支持英、日、韩、法、西、俄、阿拉伯等语种的翻译。 翻译属于增值服务，需<a href="mailto:aiui_support@iflytek.com" target="_blank" rel="noreferrer">联系AIUI开启</a>。</p><h3 id="_2-7-交互认知大模型" tabindex="-1">2.7. 交互认知大模型 <a class="header-anchor" href="#_2-7-交互认知大模型" aria-label="Permalink to &quot;2.7. 交互认知大模型&quot;">​</a></h3><p>AIUI支持配置交互大模型服务能力，在传统语义基础上，提高多轮交互、闲聊问答效果。</p><h2 id="aiui交互指导" tabindex="-1">AIUI交互指导 <a class="header-anchor" href="#aiui交互指导" aria-label="Permalink to &quot;AIUI交互指导&quot;">​</a></h2><h3 id="_3-1-按键交互" tabindex="-1">3.1. 按键交互 <a class="header-anchor" href="#_3-1-按键交互" aria-label="Permalink to &quot;3.1. 按键交互&quot;">​</a></h3><p>设备有录音按钮，按下录音，松开后停止录音。</p><h3 id="_3-2-语音唤醒交互" tabindex="-1">3.2. 语音唤醒交互 <a class="header-anchor" href="#_3-2-语音唤醒交互" aria-label="Permalink to &quot;3.2. 语音唤醒交互&quot;">​</a></h3><p>用户先喊唤醒词，设备被唤醒后才能进行语音交互。</p><h3 id="_3-3-全双工交互" tabindex="-1">3.3. 全双工交互 <a class="header-anchor" href="#_3-3-全双工交互" aria-label="Permalink to &quot;3.3. 全双工交互&quot;">​</a></h3><p>指设备喇叭发声的同时录音，无需唤醒词打断，用户可以跟设备对话。\`</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：小飞小飞，今天天气</span></span>
<span class="line"><span>音响：今天晴……</span></span>
<span class="line"><span>用户：明天呢</span></span>
<span class="line"><span>音响：明天多云……</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_3-4-离线语音交互" tabindex="-1">3.4. 离线语音交互 <a class="header-anchor" href="#_3-4-离线语音交互" aria-label="Permalink to &quot;3.4. 离线语音交互&quot;">​</a></h3><p>离线语音交互是将语音交互需要的服务下发至本地，通过本地解析实现原本只能在线才能支持的语音交互服务。AIUI离线语音交互服务支持开发者定制更新资源，进一步的提升设备化个性语音交互体验。</p><p><code>离线交互算力占用</code> 2核1.4G芯片：cpu占用15%；内存占用70M；</p><h3 id="_3-5-免唤醒交互" tabindex="-1">3.5. 免唤醒交互 <a class="header-anchor" href="#_3-5-免唤醒交互" aria-label="Permalink to &quot;3.5. 免唤醒交互&quot;">​</a></h3><p><a href="https://aiui.xfyun.cn/solution/wakeup" target="_blank" rel="noreferrer">免唤醒语音交互</a>实现了直接说话控制设备；没有网络也可以使用</p><p><code>免唤醒+离线交互算力占用</code> 2核1.4G芯片：cpu占用35%，内存占用90M；</p><h3 id="_3-6-多模态交互" tabindex="-1">3.6. 多模态交互 <a class="header-anchor" href="#_3-6-多模态交互" aria-label="Permalink to &quot;3.6. 多模态交互&quot;">​</a></h3><p>多模态交互，融合声纹识别，手势识别、唇形检测、虚拟人形象等AI技术，让人机交互方式更丰富，交互过程更自然。</p><p>用户可基于业务场景选择各个能力，并通过自定义技能及技能后处理实现交互流程的设计。</p>`,61)])])}const k=e(r,[["render",o]]);export{_ as __pageData,k as default};
